import { useState } from "react";
import { submitBug } from "../api/bug";

export default function SubmitBug() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [severity, setSeverity] = useState("low");
  const [company, setCompany] = useState("");
  const [msg, setMsg] = useState("");
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMsg("");
    setError("");

    try {
      await submitBug({
        title,
        description,
        severity,
        company,
      });

      setMsg("Bug submitted successfully ✅");
      setTitle("");
      setDescription("");
      setSeverity("low");
      setCompany("");
    } catch (err) {
      setError(err.response?.data?.msg || "Submission failed");
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <div className="max-w-xl mx-auto bg-white p-6 rounded shadow">
        <h2 className="text-2xl font-bold mb-4">🐞 Submit Bug</h2>

        {msg && <p className="text-green-600 mb-3">{msg}</p>}
        {error && <p className="text-red-600 mb-3">{error}</p>}

        <form onSubmit={handleSubmit}>
          <label className="block mb-1">Title</label>
          <input
            className="w-full border p-2 mb-3"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            required
          />

          <label className="block mb-1">Description</label>
          <textarea
            className="w-full border p-2 mb-3"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
          />

          <label className="block mb-1">Severity</label>
          <select
            className="w-full border p-2 mb-3"
            value={severity}
            onChange={(e) => setSeverity(e.target.value)}
          >
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
            <option value="critical">Critical</option>
          </select>

          <label className="block mb-1">Company ID</label>
          <input
            className="w-full border p-2 mb-4"
            value={company}
            onChange={(e) => setCompany(e.target.value)}
            placeholder="Company Mongo ID"
            required
          />

          <button className="bg-blue-600 text-white px-4 py-2 rounded">
            Submit Bug
          </button>
        </form>
      </div>
    </div>
  );
}
